) {\r\n        return {\r\n\r\n            filter: null,\r\n            currentPage: 1,\r\n            sortDesc: (this.sortDir == 'desc'),\r\n            sortKey: JSON.parse(JSON.stringify(this.sortBy)),\r\n            totalRows: 0,\r\n            searchFieldId: 'search-filter-' + uniqid(),\r\n            showAdvancedFilters: false,\r\n            advancedFilters: {\r\n                gene_symbol: '',\r\n                mode_of_inheritance: '',\r\n                mondo_id: '',\r\n                expert_panel: '',\r\n                curator: '',\r\n                current_status: '',\r\n                id: ''\r\n            },\r\n            fields: [\r\n                {\r\n                    key: 'gene_symbol',\r\n                    label: 'Gene Symbol',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'mode_of_inheritance',\r\n                    label: 'MOI',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'mondo_id',\r\n                    label: 'Disease Entity',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    thStyle: { width: '9rem' },\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'expert_panel',\r\n                    label: 'Expert Panel',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'curator',\r\n                    label: 'Curator',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'current_status',\r\n                    label: 'Status',\r\n                    sortable: false,\r\n                    filterable: true,\r\n                    thStyle: { width: '8rem' },\r\n                    advancedFilter: {\r\n                        type: 'select',\r\n                        options: [\r\n                            { value: '', text: 'Any' },\r\n                            { value: 'Uploaded', text: 'Uploaded' },\r\n                            { value: 'Precuration', text: 'Precuration' },\r\n                            { value: 'Disease entity assigned', text: 'Disease entity assigned' },\r\n                            { value: 'Precuration Complete', text: 'Precuration Complete' },\r\n                            { value: 'Curation Provisional', text: 'Curation Provisional' },\r\n                            { value: 'Curation Approved', text: 'Curation Approved' },\r\n                            { value: 'Recuration assigned', text: 'Recuration assigned' },\r\n                            { value: 'Retired Assignment', text: 'Retired Assignment' },\r\n                            { value: 'Published', text: 'Published' }\r\n                        ]\r\n                    }\r\n                },\r\n                {\r\n                    key: 'id',\r\n                    label: 'Precuration ID',\r\n                    sortable: true,\r\n                    filterable: true,\r\n                    advancedFilter: { type: 'text' }\r\n                },\r\n                {\r\n                    key: 'actions',\r\n                    label: '',\r\n                    sortable: false,\r\n                    thStyle: { width: '7rem' }\r\n                }\r\n            ],\r\n            ctx: null\r\n        }\r\n    },\r\n    computed: {\r\n        ...mapGetters({ user: 'getUser' }),\r\n\r\n        loading: function () {\r\n            return false\r\n        },\r\n\r\n        filterableFields() {\r\n            return this.fields.filter(f => f.filterable)\r\n        },\r\n\r\n        hasActiveFilters() {\r\n            if (this.filter && this.filter.trim() !== '') {\r\n                return true\r\n            }\r\n\r\n            return Object.values(this.advancedFilters).some(value => {\r\n                return value !== null && value !== undefined && String(value).trim() !== ''\r\n            })\r\n        },\r\n\r\n        activeFilterCount() {\r\n            return Object.values(this.advancedFilters).filter(value => {\r\n                return value !== null && value !== undefined && String(value).trim() !== ''\r\n            }).length\r\n        }\r\n    },\r\n    watch: {\r\n        filter: function (to, from) {\r\n            if (to !== from) {\r\n                this.resetCurrentPage()\r\n                this.$refs.table.refresh()\r\n            }\r\n        },\r\n        advancedFilters: {\r\n            deep: true,\r\n            handler() {\r\n                this.resetCurrentPage()\r\n                this.$refs.table.refresh()\r\n            }\r\n        }\r\n    },\r\n    methods: {\r\n        curationProvider(ctx, callback) {\r\n            if (ctx == this.ctx) {\r\n                return;\r\n            }\r\n\r\n            const context = {...ctx, ...this.searchParams, filters: JSON.stringify(this.advancedFilters)}\r\n            getPageOfCurations(context)\r\n                .then(response => {\r\n                    this.totalRows = response.data.meta.total\r\n                    callback(response.data.data)\r\n                })\r\n        },\r\n\r\n        clearFilters() {\r\n            this.filter = null\r\n            this.advancedFilters = {\r\n                gene_symbol: '',\r\n                mode_of_inheritance: '',\r\n                mondo_id: '',\r\n                expert_panel: '',\r\n                curator: '',\r\n                current_status: '',\r\n                id: ''\r\n   